import { useState, useRef } from 'react';
import { useIsomorphicLayoutEffect as useLayoutEffect } from '../../../../hooks';

function useSyncState<T>(state: T, initialState?: T) {
  const isUpdate = useRef<boolean>(false);
  const [currentState, setCurrentState] = useState<T>(initialState !== undefined ? (initialState as T) : state);

  useLayoutEffect(() => {
    if (!isUpdate.current) {
      isUpdate.current = true;
      return;
    }
    setCurrentState(state);
  }, [state]);

  return [currentState, setCurrentState] as const;
}

export default useSyncState;
